 25 struct KnownFPClass {
 26   /// Floating-point classes the value could be one of.
 27   FPClassTest KnownFPClasses = fcAllFlags;
 28 
 29   /// std::nullopt if the sign bit is unknown, true if the sign bit is
 30   /// definitely set or false if the sign bit is definitely unset.
 31   std::optional<bool> SignBit;
 32 
 33   KnownFPClass(FPClassTest Known = fcAllFlags, std::optional<bool> Sign = {})
 34       : KnownFPClasses(Known), SignBit(Sign) {}
 35   LLVM_ABI KnownFPClass(const APFloat &C);
 36 
 37   bool operator==(KnownFPClass Other) const {
 38     return KnownFPClasses == Other.KnownFPClasses && SignBit == Other.SignBit;
 39   }
 40 
 41   /// Return true if it's known this can never be one of the mask entries.
 42   bool isKnownNever(FPClassTest Mask) const {
 43     return (KnownFPClasses & Mask) == fcNone;
 44   }
 45 
 46   bool isKnownAlways(FPClassTest Mask) const { return isKnownNever(~Mask); }
 47 
 48   bool isUnknown() const { return KnownFPClasses == fcAllFlags && !SignBit; }
 49 
 50   /// Return true if it's known this can never be a nan.
 51   bool isKnownNeverNaN() const { return isKnownNever(fcNan); }
 52 
 53   /// Return true if it's known this must always be a nan.
 54   bool isKnownAlwaysNaN() const { return isKnownAlways(fcNan); }
 55 
 56   /// Return true if it's known this can never be an infinity.
 57   bool isKnownNeverInfinity() const { return isKnownNever(fcInf); }
 58 
 59   /// Return true if it's known this can never be an infinity or nan
 60   bool isKnownNeverInfOrNaN() const { return isKnownNever(fcInf | fcNan); }
 61 
 62   /// Return true if it's known this can never be +infinity.
 63   bool isKnownNeverPosInfinity() const { return isKnownNever(fcPosInf); }
 64 
 65   /// Return true if it's known this can never be -infinity.
 66   bool isKnownNeverNegInfinity() const { return isKnownNever(fcNegInf); }
 67 
 68   /// Return true if it's known this can never be a subnormal
 69   bool isKnownNeverSubnormal() const { return isKnownNever(fcSubnormal); }
 70 
 71   /// Return true if it's known this can never be a positive subnormal
 72   bool isKnownNeverPosSubnormal() const { return isKnownNever(fcPosSubnormal); }
 73 
 74   /// Return true if it's known this can never be a negative subnormal
 75   bool isKnownNeverNegSubnormal() const { return isKnownNever(fcNegSubnormal); }
 76 
 77   /// Return true if it's known this can never be a zero. This means a literal
 78   /// [+-]0, and does not include denormal inputs implicitly treated as [+-]0.
 79   bool isKnownNeverZero() const { return isKnownNever(fcZero); }
 80 
 81   /// Return true if it's known this can never be a literal positive zero.
 82   bool isKnownNeverPosZero() const { return isKnownNever(fcPosZero); }
 83 
 84   /// Return true if it's known this can never be a negative zero. This means a
 85   /// literal -0 and does not include denormal inputs implicitly treated as -0.
 86   bool isKnownNeverNegZero() const { return isKnownNever(fcNegZero); }
 87 
 88   /// Return true if it's known this can never be interpreted as a zero. This
 89   /// extends isKnownNeverZero to cover the case where the assumed
 90   /// floating-point mode for the function interprets denormals as zero.
 91   LLVM_ABI bool isKnownNeverLogicalZero(DenormalMode Mode) const;
 92 
 93   /// Return true if it's known this can never be interpreted as a negative
 94   /// zero.
 95   LLVM_ABI bool isKnownNeverLogicalNegZero(DenormalMode Mode) const;
 96 
 97   /// Return true if it's known this can never be interpreted as a positive
 98   /// zero.
 99   LLVM_ABI bool isKnownNeverLogicalPosZero(DenormalMode Mode) const;
100 
101   static constexpr FPClassTest OrderedLessThanZeroMask =
102       fcNegSubnormal | fcNegNormal | fcNegInf;
103   static constexpr FPClassTest OrderedGreaterThanZeroMask =
104       fcPosSubnormal | fcPosNormal | fcPosInf;
105 
106   /// Return true if we can prove that the analyzed floating-point value is
107   /// either NaN or never less than -0.0.
108   ///
109   ///      NaN --> true
110   ///       +0 --> true
111   ///       -0 --> true
112   ///   x > +0 --> true
113   ///   x < -0 --> false
114   bool cannotBeOrderedLessThanZero() const {
115     return isKnownNever(OrderedLessThanZeroMask);
116   }
117 
118   /// Return true if we can prove that the analyzed floating-point value is
119   /// either NaN or never greater than -0.0.
120   ///      NaN --> true
121   ///       +0 --> true
122   ///       -0 --> true
123   ///   x > +0 --> false
124   ///   x < -0 --> true
125   bool cannotBeOrderedGreaterThanZero() const {
126     return isKnownNever(OrderedGreaterThanZeroMask);
127   }
128 
129   /// Return true if it's know this can never be a negative value or a logical
130   /// 0.
131   ///
132   ///      NaN --> true
133   ///  x >= -0 --> false
134   ///     nsub --> true if mode is ieee, false otherwise.
135   ///   x < -0 --> true
136   bool cannotBeOrderedGreaterEqZero(DenormalMode Mode) const {
137     return isKnownNever(fcPositive) && isKnownNeverLogicalNegZero(Mode);
138   }
139 
140   KnownFPClass intersectWith(const KnownFPClass &RHS) const {
141     return KnownFPClass(KnownFPClasses | RHS.KnownFPClasses,
142                         SignBit == RHS.SignBit ? SignBit : std::nullopt);
143   }
144 
145   KnownFPClass unionWith(const KnownFPClass &RHS) const {
146     std::optional<bool> MergedSignBit;
147     if (SignBit && !RHS.SignBit)
148       MergedSignBit = SignBit;
149     else if (!SignBit && RHS.SignBit)
150       MergedSignBit = RHS.SignBit;
151 
152     return KnownFPClass(KnownFPClasses & RHS.KnownFPClasses, MergedSignBit);
153   }
154 
155   KnownFPClass &operator|=(const KnownFPClass &RHS) {
156     KnownFPClasses = KnownFPClasses | RHS.KnownFPClasses;
157 
158     if (SignBit != RHS.SignBit)
159       SignBit = std::nullopt;
160     return *this;
161   }
162 
163   void knownNot(FPClassTest RuleOut) {
164     KnownFPClasses = KnownFPClasses & ~RuleOut;
165     if (isKnownNever(fcNan) && !SignBit) {
166       if (isKnownNever(fcNegative))
167         SignBit = false;
168       else if (isKnownNever(fcPositive))
169         SignBit = true;
170     }
171   }
172 
173   void fneg() {
174     KnownFPClasses = llvm::fneg(KnownFPClasses);
175     if (SignBit)
176       SignBit = !*SignBit;
177   }
178 
179   void fabs() {
180     if (KnownFPClasses & fcNegZero)
181       KnownFPClasses |= fcPosZero;
182 
183     if (KnownFPClasses & fcNegInf)
184       KnownFPClasses |= fcPosInf;
185 
186     if (KnownFPClasses & fcNegSubnormal)
187       KnownFPClasses |= fcPosSubnormal;
188 
189     if (KnownFPClasses & fcNegNormal)
190       KnownFPClasses |= fcPosNormal;
191 
192     signBitMustBeZero();
193   }
194 
195   // Enum of min/max intrinsics to avoid dependency on IR.
196   enum class MinMaxKind {
197     minimum,
198     maximum,
199     minimumnum,
200     maximumnum,
201     minnum,
202     maxnum
203   };
204 
205   LLVM_ABI static KnownFPClass
206   minMaxLike(const KnownFPClass &LHS, const KnownFPClass &RHS, MinMaxKind Kind,
207              DenormalMode DenormMode = DenormalMode::getDynamic());
208 
209   /// Apply the canonicalize intrinsic to this value. This is essentially a
210   /// stronger form of propagateCanonicalizingSrc.
211   LLVM_ABI static KnownFPClass
212   canonicalize(const KnownFPClass &Src,
213                DenormalMode DenormMode = DenormalMode::getDynamic());
214 
215   /// Report known values for fadd
216   LLVM_ABI static KnownFPClass
217   fadd(const KnownFPClass &LHS, const KnownFPClass &RHS,
218        DenormalMode Mode = DenormalMode::getDynamic());
219 
220   /// Report known values for fadd x, x
221   LLVM_ABI static KnownFPClass
222   fadd_self(const KnownFPClass &Src,
223             DenormalMode Mode = DenormalMode::getDynamic());
224 
225   /// Report known values for fmul
226   LLVM_ABI static KnownFPClass
227   fmul(const KnownFPClass &LHS, const KnownFPClass &RHS,
228        DenormalMode Mode = DenormalMode::getDynamic());
229 
230   // Special case of fmul x, x.
231   static KnownFPClass square(const KnownFPClass &Src,
232                              DenormalMode Mode = DenormalMode::getDynamic()) {
233     KnownFPClass Known = fmul(Src, Src, Mode);
234 
235     // X * X is always non-negative or a NaN.
236     Known.knownNot(fcNegative);
237     return Known;
238   }
239 
240   /// Report known values for exp, exp2 and exp10.
241   LLVM_ABI static KnownFPClass exp(const KnownFPClass &Src);
242 
243   /// Return true if the sign bit must be 0, ignoring the sign of nans.
244   bool signBitIsZeroOrNaN() const { return isKnownNever(fcNegative); }
245 
246   /// Assume the sign bit is zero.
247   void signBitMustBeZero() {
248     KnownFPClasses &= (fcPositive | fcNan);
249     SignBit = false;
250   }
