4850                                     KnownFromContext);
4851 
4852       BasicBlockEdge Edge1(BI->getParent(), BI->getSuccessor(1));
4853       if (Q.DT->dominates(Edge1, Q.CxtI->getParent()))
4854         computeKnownFPClassFromCond(V, Cond, /*CondIsTrue=*/false, Q.CxtI,
